    st = tb_settle_tick(rt, tick);
    if (st != TB_OK)
      return st;

    st = tb_merge_drain(rt, tick, ord);
    if (st != TB_OK)
      return st;

    st = tb_nudge_drain(rt, tick);
    if (st != TB_OK)
      return st;
  }

  // Final drain to avoid leaving work in queues.
  for (uint32_t i = 0; i < 16; i++) {
    st = tb_settle_tick(rt, sc.ticks + i);
    if (st != TB_OK)
