    st = tb_merge_drain(rt, sc.ticks + i, ord);
    if (st != TB_OK)
      return st;
    st = tb_nudge_drain(rt, sc.ticks + i);
    if (st != TB_OK)
      return st;
  }

  return TB_OK;
}

