bool tb_vec_ev_init(tb_vec_ev *a, size_t cap) {
  if (!a)
    return false;
  if (cap == 0)
    cap = 16;
  a->v = (tb_event *)malloc(sizeof(tb_event) * cap);
  if (!a->v)
    return false;
  a->len = 0;
